    var txt = s.textContent || '';
    if (txt.length > 100) {
      scriptInfo.push({i: i, len: txt.length, preview: txt.substring(0, 300)});
    }
  });
  // Ищем текстовые узлы
  var allText = '';
  var walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT, null, false);
  var node;
  while (node = walker.nextNode()) {
    if (node.textContent.trim().length > 5) {
      allText += node.textContent.trim() + '\n';
      if (allText.length > 3000) break;
    }
  }
  return {
    scriptsCount: scripts.length,
    scriptsWithContent: scriptInfo,
    allTextNodes: allText.substring(0, 3000),
    htmlHead: html.substring(0, 500)
  };
})()
